# Generated by anthropic (claude-opus-4-6)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(
            name: 'ARTIFACT_URLS',
            defaultValue: '',
            description: 'Comma-separated list of artifact URLs to download (supports S3, Artifactory, HTTP/HTTPS)'
        )
        string(
            name: 'DEPLOY_SERVERS',
            defaultValue: '',
            description: 'Comma-separated list of production server hostnames/IPs to deploy to'
        )
        string(
            name: 'DEPLOY_PATH',
            defaultValue: '/opt/app/deploy',
            description: 'Target deployment path on production servers'
        )
        string(
            name: 'DEPLOY_USER',
            defaultValue: 'deploy',
            description: 'SSH user for deployment to production servers'
        )
        credentials(
            name: 'SSH_CREDENTIAL_ID',
            defaultValue: '',
            description: 'SSH credentials for connecting to production servers',
            credentialType: 'com.cloudbees.jenkins.plugins.sshcredentials.impl.BasicSSHUserPrivateKey'
        )
        credentials(
            name: 'ARTIFACTORY_CREDENTIAL_ID',
            defaultValue: '',
            description: 'Credentials for Artifactory authentication (optional)',
            credentialType: 'com.cloudbees.plugins.credentials.impl.UsernamePasswordCredentialsImpl'
        )
        credentials(
            name: 'AWS_CREDENTIAL_ID',
            defaultValue: '',
            description: 'AWS credentials for S3 downloads (optional)',
            credentialType: 'com.cloudbees.jenkins.plugins.awscredentials.AmazonWebServicesCredentials'
        )
        string(
            name: 'PRE_DEPLOY_SCRIPT',
            defaultValue: '',
            description: 'Optional script to run on each server before deployment (e.g., stop services)'
        )
        string(
            name: 'POST_DEPLOY_SCRIPT',
            defaultValue: '',
            description: 'Optional script to run on each server after deployment (e.g., start services)'
        )
        string(
            name: 'HEALTH_CHECK_URL_PATTERN',
            defaultValue: '',
            description: 'Health check URL pattern with {server} placeholder (e.g., http://{server}:8080/health)'
        )
        string(
            name: 'HEALTH_CHECK_TIMEOUT',
            defaultValue: '120',
            description: 'Health check timeout in seconds'
        )
        booleanParam(
            name: 'DRY_RUN',
            defaultValue: false,
            description: 'Perform a dry run without actually deploying'
        )
        booleanParam(
            name: 'ROLLING_DEPLOY',
            defaultValue: true,
            description: 'Deploy to servers one at a time (rolling) vs all at once'
        )
        booleanParam(
            name: 'BACKUP_EXISTING',
            defaultValue: true,
            description: 'Backup existing artifacts on production servers before deployment'
        )
    }

    environment {
        ARTIFACTS_DIR = "${WORKSPACE}/artifacts"
        CHECKSUMS_DIR = "${WORKSPACE}/checksums"
        DEPLOY_TIMESTAMP = sh(script: 'date +%Y%m%d_%H%M%S', returnStdout: true).trim()
    }

    options {
        timeout(time: 60, unit: 'MINUTES')
        timestamps()
        buildDiscarder(logRotator(numToKeepStr: '30'))
        disableConcurrentBuilds()
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    echo "=== Validating Pipeline Parameters ==="

                    if (!params.ARTIFACT_URLS?.trim()) {
                        error "ARTIFACT_URLS parameter is required. Provide comma-separated URLs."
                    }

                    if (!params.DEPLOY_SERVERS?.trim()) {
                        error "DEPLOY_SERVERS parameter is required. Provide comma-separated server addresses."
                    }

                    if (!params.DEPLOY_PATH?.trim()) {
                        error "DEPLOY_PATH parameter is required."
                    }

                    env.ARTIFACT_URL_LIST = params.ARTIFACT_URLS.trim()
                    env.SERVER_LIST = params.DEPLOY_SERVERS.trim()

                    def urls = env.ARTIFACT_URL_LIST.split(',').collect { it.trim() }.findAll { it }
                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }

                    echo "Artifacts to download (${urls.size()}):"
                    urls.eachWithIndex { url, idx ->
                        echo "  [${idx + 1}] ${url}"
                    }

                    echo "Target servers (${servers.size()}):"
                    servers.eachWithIndex { server, idx ->
                        echo "  [${idx + 1}] ${server}"
                    }

                    echo "Deploy path: ${params.DEPLOY_PATH}"
                    echo "Deploy user: ${params.DEPLOY_USER}"
                    echo "Rolling deploy: ${params.ROLLING_DEPLOY}"
                    echo "Backup existing: ${params.BACKUP_EXISTING}"
                    echo "Dry run: ${params.DRY_RUN}"

                    if (params.DRY_RUN) {
                        echo "*** DRY RUN MODE - No actual deployment will occur ***"
                    }
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                script {
                    echo "=== Preparing Workspace ==="
                    sh """
                        rm -rf ${ARTIFACTS_DIR} ${CHECKSUMS_DIR}
                        mkdir -p ${ARTIFACTS_DIR}
                        mkdir -p ${CHECKSUMS_DIR}
                    """
                }
            }
        }

        stage('Download Artifacts') {
            steps {
                script {
                    echo "=== Downloading Artifacts ==="
                    def urls = env.ARTIFACT_URL_LIST.split(',').collect { it.trim() }.findAll { it }
                    def downloadResults = [:]

                    for (int i = 0; i < urls.size(); i++) {
                        def url = urls[i]
                        def fileName = extractFileName(url)
                        def targetPath = "${ARTIFACTS_DIR}/${fileName}"

                        echo "Downloading [${i + 1}/${urls.size()}]: ${url}"
                        echo "  -> ${targetPath}"

                        try {
                            downloadArtifact(url, targetPath)
                            
                            // Generate checksum
                            def checksum = sh(
                                script: "sha256sum ${targetPath} | awk '{print \$1}'",
                                returnStdout: true
                            ).trim()

                            sh "echo '${checksum}  ${fileName}' >> ${CHECKSUMS_DIR}/sha256sums.txt"

                            def fileSize = sh(
                                script: "stat -c%s ${targetPath} 2>/dev/null || stat -f%z ${targetPath} 2>/dev/null || echo 'unknown'",
                                returnStdout: true
                            ).trim()

                            downloadResults[fileName] = [
                                url: url,
                                checksum: checksum,
                                size: fileSize,
                                status: 'SUCCESS'
                            ]

                            echo "  Checksum (SHA256): ${checksum}"
                            echo "  Size: ${fileSize} bytes"
                            echo "  Status: SUCCESS"

                        } catch (Exception e) {
                            downloadResults[fileName] = [
                                url: url,
                                status: 'FAILED',
                                error: e.getMessage()
                            ]
                            error "Failed to download artifact from ${url}: ${e.getMessage()}"
                        }
                    }

                    // Summary
                    echo "\n=== Download Summary ==="
                    downloadResults.each { name, result ->
                        echo "  ${name}: ${result.status}" + (result.status == 'SUCCESS' ? " (${result.size} bytes)" : " - ${result.error}")
                    }

                    // List all downloaded artifacts
                    sh "ls -la ${ARTIFACTS_DIR}/"
                }
            }
        }

        stage('Verify Artifacts') {
            steps {
                script {
                    echo "=== Verifying Downloaded Artifacts ==="

                    def artifactCount = sh(
                        script: "ls -1 ${ARTIFACTS_DIR}/ | wc -l",
                        returnStdout: true
                    ).trim().toInteger()

                    def expectedCount = env.ARTIFACT_URL_LIST.split(',').collect { it.trim() }.findAll { it }.size()

                    if (artifactCount != expectedCount) {
                        error "Expected ${expectedCount} artifacts but found ${artifactCount} in artifacts directory"
                    }

                    echo "All ${artifactCount} artifacts downloaded and verified successfully"

                    // Verify checksums
                    echo "\nChecksum verification:"
                    sh "cat ${CHECKSUMS_DIR}/sha256sums.txt"

                    // Verify files are not empty
                    def emptyFiles = sh(
                        script: "find ${ARTIFACTS_DIR}/ -empty -type f",
                        returnStdout: true
                    ).trim()

                    if (emptyFiles) {
                        error "Found empty artifact files: ${emptyFiles}"
                    }

                    echo "All artifacts are non-empty and checksums recorded"
                }
            }
        }

        stage('Deploy to Production') {
            when {
                expression { return !params.DRY_RUN }
            }
            steps {
                script {
                    echo "=== Deploying to Production Servers ==="
                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }
                    def deployResults = [:]

                    if (params.ROLLING_DEPLOY) {
                        echo "Using ROLLING deployment strategy"
                        for (int i = 0; i < servers.size(); i++) {
                            def server = servers[i]
                            echo "\n--- Deploying to server [${i + 1}/${servers.size()}]: ${server} ---"
                            try {
                                deployToServer(server)
                                deployResults[server] = 'SUCCESS'
                                echo "Successfully deployed to ${server}"
                            } catch (Exception e) {
                                deployResults[server] = "FAILED: ${e.getMessage()}"
                                error "Deployment failed on ${server}: ${e.getMessage()}. Stopping rolling deployment."
                            }
                        }
                    } else {
                        echo "Using PARALLEL deployment strategy"
                        def parallelStages = [:]
                        for (int i = 0; i < servers.size(); i++) {
                            def server = servers[i]
                            def index = i
                            parallelStages["Deploy to ${server}"] = {
                                echo "--- Deploying to server [${index + 1}/${servers.size()}]: ${server} ---"
                                try {
                                    deployToServer(server)
                                    deployResults[server] = 'SUCCESS'
                                    echo "Successfully deployed to ${server}"
                                } catch (Exception e) {
                                    deployResults[server] = "FAILED: ${e.getMessage()}"
                                    throw e
                                }
                            }
                        }
                        parallel parallelStages
                    }

                    // Deployment summary
                    echo "\n=== Deployment Summary ==="
                    deployResults.each { server, result ->
                        echo "  ${server}: ${result}"
                    }

                    def failedServers = deployResults.findAll { it.value != 'SUCCESS' }
                    if (failedServers) {
                        error "Deployment failed on ${failedServers.size()} server(s): ${failedServers.keySet().join(', ')}"
                    }
                }
            }
        }

        stage('Dry Run Summary') {
            when {
                expression { return params.DRY_RUN }
            }
            steps {
                script {
                    echo "=== DRY RUN SUMMARY ==="
                    echo "The following actions would be performed:"
                    echo ""

                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }
                    def artifacts = sh(script: "ls -1 ${ARTIFACTS_DIR}/", returnStdout: true).trim().split('\n')

                    echo "Artifacts to deploy:"
                    artifacts.each { artifact ->
                        echo "  - ${artifact}"
                    }

                    echo "\nTarget servers:"
                    servers.each { server ->
                        echo "  - ${server}"
                    }

                    echo "\nDeploy path: ${params.DEPLOY_PATH}"
                    echo "Deploy strategy: ${params.ROLLING_DEPLOY ? 'Rolling' : 'Parallel'}"
                    echo "Backup existing: ${params.BACKUP_EXISTING}"

                    if (params.PRE_DEPLOY_SCRIPT?.trim()) {
                        echo "\nPre-deploy script: ${params.PRE_DEPLOY_SCRIPT}"
                    }
                    if (params.POST_DEPLOY_SCRIPT?.trim()) {
                        echo "\nPost-deploy script: ${params.POST_DEPLOY_SCRIPT}"
                    }
                    if (params.HEALTH_CHECK_URL_PATTERN?.trim()) {
                        echo "\nHealth check URL pattern: ${params.HEALTH_CHECK_URL_PATTERN}"
                        echo "Health check timeout: ${params.HEALTH_CHECK_TIMEOUT}s"
                    }

                    echo "\n*** No actual deployment was performed (DRY RUN) ***"
                }
            }
        }

        stage('Health Checks') {
            when {
                allOf {
                    expression { return !params.DRY_RUN }
                    expression { return params.HEALTH_CHECK_URL_PATTERN?.trim() }
                }
            }
            steps {
                script {
                    echo "=== Running Health Checks ==="
                    def servers = env.SERVER_LIST.split(',').collect { it.trim() }.findAll { it }
                    def healthResults = [:]
                    def timeout = params.HEALTH_CHECK_TIMEOUT?.trim() ? params.HEALTH_CHECK_TIMEOUT.trim().toInteger() : 120

                    for (int i = 0; i < servers.size(); i++) {
                        def server = servers[i]
                        def healthUrl = params.HEALTH_CHECK_URL_PATTERN.replace('{server}', server)
                        echo "Checking health of ${server}: ${healthUrl}"

                        try {
                            def healthy = performHealthCheck(healthUrl, timeout)
                            healthResults[server] = healthy ? 'HEALTHY' : 'UNHEALTHY'
                        } catch (Exception e) {
                            healthResults[server] = "UNHEALTHY: ${e.getMessage()}"
                        }
                    }

                    echo "\n=== Health Check Results ==="
                    healthResults.each { server, result ->
                        echo "  ${server}: ${result}"
                    }

                    def unhealthyServers = healthResults.findAll { it.value != 'HEALTHY' }
                    if (unhealthyServers) {
                        unstable "Health check failed on ${unhealthyServers.size()} server(s): ${unhealthyServers.keySet().join(', ')}"
                    } else {
                        echo "All servers are healthy!"
                    }
                }
            }
        }
    }

    post {
        success {
            script {
                echo "=== Pipeline completed successfully ==="
                if (params.DRY_RUN) {
                    echo "This was a DRY RUN - no changes were made"
                } else {
                    echo "Artifacts deployed to: ${params.DEPLOY_SERVERS}"
                    echo "Deploy path: ${params.DEPLOY_PATH}"
                    echo "Timestamp: ${env.DEPLOY_TIMESTAMP}"
                }
            }
        }
        failure {
            script {
                echo "=== Pipeline FAILED ==="
                echo "Please check the logs above for details"
                echo "If deployment was partially completed, manual intervention may be required"
            }
        }
        unstable {
            script {
                echo "=== Pipeline completed with warnings ==="
                echo "Deployment may have succeeded but health checks reported issues"
            }
        }
        cleanup {
            script {
                echo "Cleaning up workspace artifacts..."
                sh "rm -rf ${ARTIFACTS_DIR} ${CHECKSUMS_DIR}"
            }
        }
    }
}

def extractFileName(String url) {
    // Handle S3 URLs
    if (url.startsWith('s3://')) {
        return url.tokenize('/')[-1]
    }

    // Handle HTTP/HTTPS URLs
    def cleanUrl = url.split('\\?')[0] // Remove query parameters
    def fileName = cleanUrl.tokenize('/')[-1]

    if (!fileName || fileName.isEmpty()) {
        fileName = "artifact_${System.currentTimeMillis()}"
    }

    // Decode URL-encoded characters
    fileName = java.net.URLDecoder.decode(fileName, 'UTF-8')

    return fileName
}

def downloadArtifact(String url, String targetPath) {
    if (url.startsWith('s3://')) {
        downloadFromS3(url, targetPath)
    } else if (url.contains('artifactory') || url.contains('jfrog')) {
        downloadFromArtifactory(url, targetPath)
    } else {
        downloadFromHttp(url, targetPath)
    }
}

def downloadFromS3(String s3Url, String targetPath) {
    echo "Downloading from S3: ${s3Url}"

    if (params.AWS_CREDENTIAL_ID?.trim()) {
        withCredentials([[$class: 'AmazonWebServicesCredentialsBinding',
                          credentialsId: params.AWS_CREDENTIAL_ID,
                          accessKeyVariable: 'AWS_ACCESS_KEY_ID',
                          secretKeyVariable: 'AWS_SECRET_ACCESS_KEY']]) {
            sh """
                aws s3 cp '${s3Url}' '${targetPath}' --no-progress
            """
        }
    } else {
        // Use instance profile or default credentials
        sh """
            aws s3 cp '${s3Url}' '${targetPath}' --no-progress
        """
    }
}

def downloadFromArtifactory(String url, String targetPath) {
    echo "Downloading from Artifactory: ${url}"

    if (params.ARTIFACTORY_CREDENTIAL_ID?.trim()) {
        withCredentials([usernamePassword(
            credentialsId: params.ARTIFACTORY_CREDENTIAL_ID,
            usernameVariable: 'ARTIFACTORY_USER',
            passwordVariable: 'ARTIFACTORY_PASSWORD'
        )]) {
            sh """
                curl -fsSL \
                    -u "\${ARTIFACTORY_USER}:\${ARTIFACTORY_PASSWORD}" \
                    -o '${targetPath}' \
                    '${url}'
            """
        }
    } else {
        sh """
            curl -fsSL \
                -o '${targetPath}' \
                '${url}'
        """
    }
}

def downloadFromHttp(String url, String targetPath) {
    echo "Downloading from HTTP: ${url}"

    sh """
        curl -fsSL \
            --retry 3 \
            --retry-delay 5 \
            --connect-timeout 30 \
            --max-time 600 \
            -o '${targetPath}' \
            '${url}'
    """
}

def deployToServer(String server) {
    def sshCredId = params.SSH_CREDENTIAL_ID
    def deployUser = params.DEPLOY_USER ?: 'deploy'
    def deployPath = params.DEPLOY_PATH
    def backupPath = "${deployPath}_backup_${env.DEPLOY_TIMESTAMP}"

    sshagent(credentials: [sshCredId]) {
        def sshOpts = "-o StrictHostKeyChecking=no -o ConnectTimeout=30"

        // Test SSH connectivity
        echo "Testing SSH connectivity to ${server}..."
        sh """
            ssh ${sshOpts} ${deployUser}@${server} 'echo "SSH connection successful"'
        """

        // Run pre-deploy script if provided
        if (params.PRE_DEPLOY_SCRIPT?.trim()) {
            echo "Running pre-deploy script on ${server}..."
            sh """
                ssh ${sshOpts} ${deployUser}@${server} '${params.PRE_DEPLOY_SCRIPT}'
            """
        }

        // Backup existing deployment if requested
        if (params.BACKUP_EXISTING) {
            echo "Backing up existing deployment on ${server}..."
            sh """
                ssh ${sshOpts} ${deployUser}@${server} '
                    if [ -d "${deployPath}" ]; then
                        echo "Creating backup at ${backupPath}"
                        cp -a "${deployPath}" "${backupPath}"
                        echo "Backup created successfully"
                    else
                        echo "No existing deployment found at ${deployPath}, skipping backup"
                    fi
                '
            """
        }

        // Ensure deploy directory exists
        echo "Preparing deployment directory on ${server}..."
        sh """
            ssh ${sshOpts} ${deployUser}@${server} 'mkdir -p ${deployPath}'
        """

        // Transfer artifacts
        echo "Transferring artifacts to ${server}:${deployPath}..."
        sh """
            scp ${sshOpts} -r ${ARTIFACTS_DIR}/* ${deployUser}@${server}:${deployPath}/
        """

        // Transfer checksums
        sh """
            scp ${sshOpts} ${CHECKSUMS_DIR}/sha256sums.txt ${deployUser}@${server}:${deployPath}/sha256sums.txt
        """

        // Verify checksums on remote server
        echo "Verifying artifact integrity on ${server}..."
        sh """
            ssh ${sshOpts} ${deployUser}@${server} '
                cd ${deployPath}
                if command -v sha256sum &> /dev/null; then
                    sha256sum -c sha256sums.txt
                    echo "Checksum verification passed"
                else
                    echo "sha256sum not available, skipping remote checksum verification"
                fi
            '
        """

        // Run post-deploy script if provided
        if (params.POST_DEPLOY_SCRIPT?.trim()) {
            echo "Running post-deploy script on ${server}..."
            sh """
                ssh ${sshOpts} ${deployUser}@${server} '${params.POST_DEPLOY_SCRIPT}'
            """
        }

        echo "Deployment to ${server} completed successfully"
    }
}

def performHealthCheck(String healthUrl, int timeoutSeconds) {
    def startTime = System.currentTimeMillis()
    def endTime = startTime + (timeoutSeconds * 1000)
    def checkInterval = 10 // seconds between checks
    def attempt = 0

    while (System.currentTimeMillis() < endTime) {
        attempt++
        echo "Health check attempt ${attempt}: ${healthUrl}"

        try {
            def statusCode = sh(
                script: """
                    curl -s -o /dev/null -w '%{http_code}' \
                        --connect-timeout 10 \
                        --max-time 30 \
                        '${healthUrl}'
                """,
                returnStdout: true
            ).trim()

            echo "  Response status: ${statusCode}"

            if (statusCode == '200') {
                echo "  Health check PASSED"
                return true
            }
        } catch (Exception e) {
            echo "  Health check attempt failed: ${e.getMessage()}"
        }

        if (System.currentTimeMillis() + (checkInterval * 1000) < endTime) {
            echo "  Retrying in ${checkInterval} seconds..."
            sleep(checkInterval)
        }
    }

    echo "Health check FAILED after ${timeoutSeconds} seconds (${attempt} attempts)"
    return false
}